package com.example.mobilefinalproject

import androidx.core.os.bundleOf
import androidx.fragment.app.testing.launchFragmentInContainer
import androidx.test.ext.junit.runners.AndroidJUnit4
import androidx.test.filters.MediumTest
import androidx.test.espresso.Espresso.onView
import androidx.test.espresso.assertion.ViewAssertions.matches
import androidx.test.espresso.matcher.ViewMatchers.withId
import androidx.test.espresso.matcher.ViewMatchers.withText
import com.example.mobilefinalproject.models.MockDeliveryDataSource
import com.example.mobilefinalproject.ui.driver.DriverFinderFragment
import com.example.mobilefinalproject.ui.driver.DriverFinderMapClusterer
import org.junit.Assert.assertTrue
import org.junit.Test
import org.junit.runner.RunWith

@RunWith(AndroidJUnit4::class)
@MediumTest
class DriverFinderFragmentTest {

    @Test
    fun selectingDeliveryShowsDetailBottomSheet() {
        val delivery = MockDeliveryDataSource.deliveries.first()
        val scenario = launchFinderFragment()

        scenario.onFragment { fragment ->
            fragment.handleDeliverySelection(delivery)
        }

        onView(withId(R.id.tv_order_id))
            .check(matches(withText(fragmentString(R.string.order_id_format, delivery.id))))
        onView(withId(R.id.tv_customer_name))
            .check(matches(withText(delivery.customerName)))
        onView(withId(R.id.tv_pickup_address))
            .check(matches(withText(delivery.pickupAddress)))
        onView(withId(R.id.tv_dropoff_address))
            .check(matches(withText(delivery.dropoffAddress)))
    }

    @Test
    fun zoomIntoClusterIncreasesMapZoom() {
        val scenario = launchFinderFragment()
        val cluster = DriverFinderMapClusterer.cluster(
            DriverFinderMapClusterer.toMapPoints(MockDeliveryDataSource.deliveries),
            zoom = 9.0,
        ).first { it.points.size > 1 }

        scenario.onFragment { fragment ->
            val initialZoom = fragment.currentZoomLevel()

            fragment.zoomIntoCluster(cluster.centerLatitude, cluster.centerLongitude)

            assertTrue(fragment.currentZoomLevel() > initialZoom)
        }
    }

    private fun launchFinderFragment() = launchFragmentInContainer<DriverFinderFragment>(
        fragmentArgs = bundleOf(
            DriverFinderFragment.ARG_SKIP_LOCATION_PERMISSION_CHECK to true,
        ),
        themeResId = R.style.Theme_MobileFinalProject,
    )

    private fun fragmentString(resId: Int, vararg args: Any): String {
        return androidx.test.platform.app.InstrumentationRegistry
            .getInstrumentation()
            .targetContext
            .getString(resId, *args)
    }
}

package com.example.mobilefinalproject.session

import android.content.Context
import androidx.core.content.edit
import com.example.mobilefinalproject.models.Customer
import com.example.mobilefinalproject.models.driver.Driver

object UserSessionManager {
    private const val PREFS_NAME = "user_session_prefs"
    private const val KEY_USER_TYPE = "user_type"
    private const val KEY_USER_ID = "user_id"
    private const val KEY_USER_NAME = "user_name"

    enum class UserType(val value: String) {
        DRIVER("driver"),
        CUSTOMER("customer");

        companion object {
            fun fromValue(value: String?): UserType? = entries.firstOrNull { it.value == value }
        }
    }

    data class UserSession(
        val userType: UserType,
        val userId: String,
        val fullName: String,
    )

    fun saveDriver(context: Context, driver: Driver) {
        saveSession(context, UserSession(UserType.DRIVER, driver.id, driver.fullName))
    }

    fun saveCustomer(context: Context, customer: Customer) {
        saveSession(context, UserSession(UserType.CUSTOMER, customer.id, customer.fullName))
    }

    fun saveSession(context: Context, session: UserSession) {
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE).edit {
            putString(KEY_USER_TYPE, session.userType.value)
            putString(KEY_USER_ID, session.userId)
            putString(KEY_USER_NAME, session.fullName)
        }
    }

    fun getSession(context: Context): UserSession? {
        val prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        val userType = UserType.fromValue(prefs.getString(KEY_USER_TYPE, null)) ?: return null
        val userId = prefs.getString(KEY_USER_ID, null)?.takeIf { it.isNotBlank() } ?: return null
        val fullName = prefs.getString(KEY_USER_NAME, null)?.takeIf { it.isNotBlank() } ?: return null
        return UserSession(userType, userId, fullName)
    }

    fun hasSession(context: Context): Boolean = getSession(context) != null

    fun clearSession(context: Context) {
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE).edit { clear() }
    }

    fun restoreDriver(context: Context): Driver? {
        val session = getSession(context) ?: return null
        return if (session.userType == UserType.DRIVER) {
            Driver(session.userId, session.fullName)
        } else {
            null
        }
    }

    fun restoreCustomer(context: Context): Customer? {
        val session = getSession(context) ?: return null
        return if (session.userType == UserType.CUSTOMER) {
            Customer(session.userId, session.fullName)
        } else {
            null
        }
    }
}

package com.example.mobilefinalproject.ui.auth

import android.os.Bundle
import androidx.fragment.app.Fragment
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.navigation.fragment.findNavController
import com.example.mobilefinalproject.databinding.FragmentLoginBinding
import com.google.android.material.button.MaterialButton

class LoginFragment : Fragment() {

    private var binding: FragmentLoginBinding? = null

    private var selectedUserType: UserType = UserType.DRIVER

    enum class UserType {
        DRIVER, CUSTOMER
    }

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View? {
        binding = FragmentLoginBinding.inflate(inflater, container, false)
        return binding?.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)
        setupUserTypeToggle()
        setupRegisterLink()
        setupLoginButton()
    }

    private fun setupLoginButton() {
        binding?.loginButton?.setOnClickListener {
            // TODO: Add validation and actual authentication
            // For now, assume successful login
            when (selectedUserType) {
                UserType.DRIVER -> {
                    // Navigate to Driver Container Fragment using Navigation Component
                    findNavController().navigate(com.example.mobilefinalproject.R.id.action_loginFragment_to_driverContainerFragment)
                }
                UserType.CUSTOMER -> {
                    // Navigate to Customer Container Fragment using Navigation Component
                    findNavController().navigate(com.example.mobilefinalproject.R.id.action_loginFragment_to_customerContainerFragment)
                }
            }
        }
    }
    private fun setupRegisterLink() {
        binding?.registerLinkTextView?.setOnClickListener {
            findNavController().navigate(com.example.mobilefinalproject.R.id.action_loginFragment_to_registerFragment)
        }
    }

    private fun setupUserTypeToggle() {
        updateButtonStates(UserType.DRIVER)

        binding?.driverButton?.setOnClickListener {
            if (selectedUserType != UserType.DRIVER) {
                selectedUserType = UserType.DRIVER
                updateButtonStates(UserType.DRIVER)
            }
        }

        binding?.customerButton?.setOnClickListener {
            if (selectedUserType != UserType.CUSTOMER) {
                selectedUserType = UserType.CUSTOMER
                updateButtonStates(UserType.CUSTOMER)
            }
        }
    }

    private fun updateButtonStates(selectedType: UserType) {
        when (selectedType) {
            UserType.DRIVER -> {
                // Driver button filled, Customer button outlined
                setButtonFilled(binding?.driverButton)
                setButtonOutlined(binding?.customerButton)
            }
            UserType.CUSTOMER -> {
                // Customer button filled, Driver button outlined
                setButtonFilled(binding?.customerButton)
                setButtonOutlined(binding?.driverButton)
            }
        }
    }

    private fun setButtonFilled(button: MaterialButton?) {
        button?.setBackgroundColor(resources.getColor(com.example.mobilefinalproject.R.color.teal_700, null))
        button?.setTextColor(resources.getColor(android.R.color.white, null))
    }

    private fun setButtonOutlined(button: MaterialButton?) {
        button?.setBackgroundColor(resources.getColor(android.R.color.white, null))
        button?.setTextColor(resources.getColor(com.example.mobilefinalproject.R.color.teal_700, null))
    }

    override fun onDestroyView() {
        super.onDestroyView()
        binding = null
    }
}

package com.example.mobilefinalproject.ui.auth

import android.os.Bundle
import androidx.fragment.app.Fragment
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.fragment.app.activityViewModels
import androidx.navigation.fragment.findNavController
import com.example.mobilefinalproject.databinding.FragmentLoginBinding
import com.example.mobilefinalproject.models.Customer
import com.example.mobilefinalproject.models.driver.Driver
import com.example.mobilefinalproject.session.UserSessionManager
import com.example.mobilefinalproject.viewmodels.CustomerViewModel
import com.example.mobilefinalproject.viewmodels.DriverViewModel
import com.google.android.material.button.MaterialButton

class LoginFragment : Fragment() {

    private var binding: FragmentLoginBinding? = null
    private val driverViewModel: DriverViewModel by activityViewModels()
    private val customerViewModel: CustomerViewModel by activityViewModels()

    private var selectedUserType: UserType = UserType.DRIVER

    enum class UserType {
        DRIVER, CUSTOMER
    }

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View? {
        binding = FragmentLoginBinding.inflate(inflater, container, false)
        return binding?.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        if (savedInstanceState == null && tryRestoreSavedSession()) {
            return
        }

        setupUserTypeToggle()
        setupRegisterLink()
        setupLoginButton()
    }

    private fun tryRestoreSavedSession(): Boolean {
        val session = UserSessionManager.getSession(requireContext()) ?: return false

        when (session.userType) {
            UserSessionManager.UserType.DRIVER -> {
                val driver = Driver(session.userId, session.fullName)
                driverViewModel.setDriver(driver)
                findNavController().navigate(com.example.mobilefinalproject.R.id.action_loginFragment_to_driverContainerFragment)
            }
            UserSessionManager.UserType.CUSTOMER -> {
                val customer = Customer(session.userId, session.fullName)
                customerViewModel.setCustomer(customer)
                findNavController().navigate(com.example.mobilefinalproject.R.id.action_loginFragment_to_customerContainerFragment)
            }
        }

        return true
    }

    private fun setupLoginButton() {
        binding?.loginButton?.setOnClickListener {
            // TODO: Add validation and actual authentication
            // For now, assume successful login
            when (selectedUserType) {
                UserType.DRIVER -> {
                    val driver = Driver("123456789", "John Driver")
                    driverViewModel.setDriver(driver)
                    UserSessionManager.saveDriver(requireContext(), driver)
                    findNavController().navigate(com.example.mobilefinalproject.R.id.action_loginFragment_to_driverContainerFragment)
                }
                UserType.CUSTOMER -> {
                    val customer = Customer("123456789", "John Customer")
                    customerViewModel.setCustomer(customer)
                    UserSessionManager.saveCustomer(requireContext(), customer)
                    findNavController().navigate(com.example.mobilefinalproject.R.id.action_loginFragment_to_customerContainerFragment)
                }
            }
        }
    }
    private fun setupRegisterLink() {
        binding?.registerLinkTextView?.setOnClickListener {
            findNavController().navigate(com.example.mobilefinalproject.R.id.action_loginFragment_to_registerFragment)
        }
    }

    private fun setupUserTypeToggle() {
        updateButtonStates(UserType.DRIVER)

        binding?.driverButton?.setOnClickListener {
            if (selectedUserType != UserType.DRIVER) {
                selectedUserType = UserType.DRIVER
                updateButtonStates(UserType.DRIVER)
            }
        }

        binding?.customerButton?.setOnClickListener {
            if (selectedUserType != UserType.CUSTOMER) {
                selectedUserType = UserType.CUSTOMER
                updateButtonStates(UserType.CUSTOMER)
            }
        }
    }

    private fun updateButtonStates(selectedType: UserType) {
        when (selectedType) {
            UserType.DRIVER -> {
                // Driver button filled, Customer button outlined
                setButtonFilled(binding?.driverButton)
                setButtonOutlined(binding?.customerButton)
            }
            UserType.CUSTOMER -> {
                // Customer button filled, Driver button outlined
                setButtonFilled(binding?.customerButton)
                setButtonOutlined(binding?.driverButton)
            }
        }
    }

    private fun setButtonFilled(button: MaterialButton?) {
        button?.setBackgroundColor(resources.getColor(com.example.mobilefinalproject.R.color.teal_700, null))
        button?.setTextColor(resources.getColor(android.R.color.white, null))
    }

    private fun setButtonOutlined(button: MaterialButton?) {
        button?.setBackgroundColor(resources.getColor(android.R.color.white, null))
        button?.setTextColor(resources.getColor(com.example.mobilefinalproject.R.color.teal_700, null))
    }

    override fun onDestroyView() {
        super.onDestroyView()
        binding = null
    }
}

package com.example.mobilefinalproject.ui.customer

import android.os.Bundle
import androidx.fragment.app.Fragment
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.lifecycle.ViewModelProvider
import androidx.navigation.fragment.NavHostFragment
import androidx.navigation.ui.setupWithNavController
import com.example.mobilefinalproject.databinding.FragmentCustomerContainerBinding
import com.example.mobilefinalproject.models.Customer
import com.example.mobilefinalproject.viewmodels.CustomerViewModel
import com.example.mobilefinalproject.R

class CustomerContainerFragment : Fragment() {

    private var binding: FragmentCustomerContainerBinding? = null
    private lateinit var customerViewModel: CustomerViewModel

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View? {
        binding = FragmentCustomerContainerBinding.inflate(inflater, container, false)
        return binding?.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        // Initialize ViewModel at activity scope
        customerViewModel = ViewModelProvider(requireActivity())[CustomerViewModel::class.java]

        // TODO: Get driver from arguments or authentication
        val customer = Customer("123456789", "John Customer")

        // Set customer in ViewModel (accessible throughout the app)
        customerViewModel.setCustomer(customer)

        // Get NavController from nested NavHostFragment
        val navHostFragment = binding?.let {
            childFragmentManager.findFragmentById(it.customerNavHostFragment.id) as NavHostFragment
        } ?: return
        val navController = navHostFragment.navController

        // Setup automatic navigation using customer_nav_graph
        binding?.customerBottomNavigation?.setupWithNavController(navController)

        // Hide bottom navigation on edit profile screen
        navController.addOnDestinationChangedListener { _, destination, _ ->
            when (destination.id) {
                R.id.customerEditProfileFragment -> {
                    binding?.customerBottomNavigation?.visibility = View.GONE
                }
                else -> {
                    binding?.customerBottomNavigation?.visibility = View.VISIBLE
                }
            }
        }
    }
}

package com.example.mobilefinalproject.ui.customer

import android.os.Bundle
import androidx.fragment.app.Fragment
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.lifecycle.ViewModelProvider
import androidx.navigation.fragment.NavHostFragment
import androidx.navigation.ui.setupWithNavController
import com.example.mobilefinalproject.databinding.FragmentCustomerContainerBinding
import com.example.mobilefinalproject.models.Customer
import com.example.mobilefinalproject.models.MockDeliveryDataSource
import com.example.mobilefinalproject.viewmodels.CustomerViewModel
import com.example.mobilefinalproject.viewmodels.DeliveryViewModel
import com.example.mobilefinalproject.R

class CustomerContainerFragment : Fragment() {

    private var binding: FragmentCustomerContainerBinding? = null
    private lateinit var customerViewModel: CustomerViewModel
    private lateinit var deliveryViewModel: DeliveryViewModel

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View? {
        binding = FragmentCustomerContainerBinding.inflate(inflater, container, false)
        return binding?.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        // Initialize ViewModel at activity scope
        customerViewModel = ViewModelProvider(requireActivity())[CustomerViewModel::class.java]
        deliveryViewModel = ViewModelProvider(requireActivity())[DeliveryViewModel::class.java]

        val customer = customerViewModel.customer.value ?: Customer("123456789", "John Customer")

        if (customerViewModel.customer.value == null) {
            customerViewModel.setCustomer(customer)
        }
        deliveryViewModel.setCustomerDeliveries(MockDeliveryDataSource.getDeliveriesByCustomer(customer.id))

        // Get NavController from nested NavHostFragment
        val navHostFragment = binding?.let {
            childFragmentManager.findFragmentById(it.customerNavHostFragment.id) as NavHostFragment
        } ?: return
        val navController = navHostFragment.navController

        // Setup automatic navigation using customer_nav_graph
        binding?.customerBottomNavigation?.setupWithNavController(navController)

        // Hide bottom navigation on edit profile screen
        navController.addOnDestinationChangedListener { _, destination, _ ->
            when (destination.id) {
                R.id.customerEditProfileFragment -> {
                    binding?.customerBottomNavigation?.visibility = View.GONE
                }
                else -> {
                    binding?.customerBottomNavigation?.visibility = View.VISIBLE
                }
            }
        }
    }

    override fun onDestroyView() {
        super.onDestroyView()
        binding = null
    }
}

package com.example.mobilefinalproject.ui.customer

import android.net.Uri
import android.os.Bundle
import androidx.fragment.app.Fragment
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.activity.result.contract.ActivityResultContracts
import androidx.activity.result.PickVisualMediaRequest
import androidx.core.content.ContextCompat
import android.content.pm.PackageManager
import androidx.fragment.app.activityViewModels
import androidx.navigation.fragment.findNavController
import com.example.mobilefinalproject.R
import com.example.mobilefinalproject.databinding.FragmentCustomerEditProfileBinding
import com.example.mobilefinalproject.viewmodels.CustomerViewModel
import com.squareup.picasso.Picasso

class CustomerEditProfileFragment : Fragment() {

    private val customerViewModel: CustomerViewModel by activityViewModels()
    private var binding: FragmentCustomerEditProfileBinding? = null
    private var selectedImageUri: Uri? = null

    // Image picker launcher
    private val imagePickerLauncher = registerForActivityResult(
        ActivityResultContracts.PickVisualMedia()
    ) { uri ->
        uri?.let {
            selectedImageUri = it
            binding?.customerEditProfileImageView?.let { imageView ->
                Picasso.get()
                    .load(selectedImageUri)
                    .into(imageView)
            }
        }
    }

    // Permission request launcher
    private val permissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { isGranted ->
        if (isGranted) {
            imagePickerLauncher.launch(
                PickVisualMediaRequest(ActivityResultContracts.PickVisualMedia.ImageOnly)
            )
        }
    }

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View? {
        binding = FragmentCustomerEditProfileBinding.inflate(inflater, container, false)
        return binding?.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        // Observe customer data and populate fields
        customerViewModel.customer.observe(viewLifecycleOwner) { customer ->
            if (customer != null) {
                binding?.customerEditProfileFullNameEditText?.setText(customer.fullName)
                binding?.customerEditProfileIdEditText?.setText(customer.id)
            }
        }

        // Setup button click listeners
        binding?.customerEditProfileSaveButton?.setOnClickListener {
            saveProfile()
        }

        binding?.customerEditProfileCancelButton?.setOnClickListener {
            findNavController().navigateUp()
        }

        binding?.customerEditProfileChangePictureButton?.setOnClickListener {
            checkAndRequestGalleryPermission()
        }
    }

    private fun checkAndRequestGalleryPermission() {
        val permission =
            android.Manifest.permission.READ_MEDIA_IMAGES

        when {
            ContextCompat.checkSelfPermission(
                requireContext(),
                permission
            ) == PackageManager.PERMISSION_GRANTED -> {
                imagePickerLauncher.launch(
                    PickVisualMediaRequest(ActivityResultContracts.PickVisualMedia.ImageOnly)
                )
            }
            else -> {
                permissionLauncher.launch(permission)
            }
        }
    }

    private fun saveProfile() {
        val binding = binding ?: return
        val updatedFullName = binding.customerEditProfileFullNameEditText.text.toString().trim()

        if (updatedFullName.isEmpty()) {
            binding.customerEditProfileFullNameEditText.error = "Full name cannot be empty"
            return
        }

        // Get current customer from ViewModel
        val currentCustomer = customerViewModel.customer.value
        if (currentCustomer != null) {
            val updatedCustomer = currentCustomer.copy(fullName = updatedFullName)
            customerViewModel.updateCustomer(updatedCustomer)
            findNavController().navigateUp()
        }
    }
}

